import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
import { FileText, Utensils, Sparkles, ArrowLeft } from "lucide-react";
import { useUserRole } from "@/hooks/useUserRole";
import { useSmartBack } from "@/hooks/useSmartBack";

const CreatePostSelect = () => {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const goBack = useSmartBack("/community");
  const { canCreateRecipe } = useUserRole();
  const canCreateRecipeDirectly = canCreateRecipe;

  const options = [
    {
      key: "post",
      icon: FileText,
      title: t("community.postType.post", "发布帖子"),
      desc: t("community.postType.postDesc", "分享美食体验和想法"),
      onClick: () => navigate("/community/create/post"),
    },
    ...(canCreateRecipeDirectly
      ? [
          {
            key: "recipe",
            icon: Utensils,
            title: t("community.postType.recipe", "发布食谱"),
            desc: t("community.postType.recipeDesc", "分享烹饪教程和菜谱"),
            onClick: () => navigate("/community/create/recipe"),
          },
        ]
      : []),
    {
      key: "ai",
      icon: Sparkles,
      title: t("community.postType.aiRecipe", "AI 食谱"),
      desc: t("community.postType.aiRecipeDesc", "AI 识别食材并生成菜谱"),
      onClick: () => navigate("/ai-recipe", { state: { from: "/community" } }),
    },
  ];

  return (
    <div className="min-h-screen bg-background">
      {/* Header */}
      <div className="border-b bg-background sticky top-0 z-10">
        <div className="container mx-auto max-w-2xl flex items-center gap-3 px-4 py-3">
          <button
            type="button"
            onClick={goBack}
            className="p-1 -ml-1 hover:bg-muted rounded-md transition-colors"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <h1 className="font-medium">{t("community.create", "发布")}</h1>
        </div>
      </div>

      {/* Content */}
      <div className="container mx-auto max-w-2xl px-4 py-12">
        <div className="text-center mb-10">
          <h2 className="text-2xl font-semibold mb-2">
            {t("community.selectPostType", "选择发布类型")}
          </h2>
          <p className="text-muted-foreground">
            {t("community.selectPostTypeDesc", "选择您想要发布的内容类型")}
          </p>
        </div>

        <div className="grid gap-4 max-w-md mx-auto">
          {options.map((opt) => (
            <button
              key={opt.key}
              onClick={opt.onClick}
              className="flex items-center gap-4 p-5 rounded-xl border-2 border-border hover:border-primary hover:bg-primary/5 transition-all duration-200 group text-left"
            >
              <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center group-hover:bg-primary/20 transition-colors shrink-0">
                <opt.icon className="h-6 w-6 text-primary" />
              </div>
              <div>
                <h3 className="font-medium">{opt.title}</h3>
                <p className="text-sm text-muted-foreground mt-0.5">{opt.desc}</p>
              </div>
            </button>
          ))}
        </div>
      </div>
    </div>
  );
};

export default CreatePostSelect;
